sql:
SELECT COUNT(*) AS bowl_game_count
FROM bowls
WHERE location = 'Miami';

external_knowledge:
- Total yards = rushing yards + passing yards; 
- A high average total yards indicates a team's strong performance in a game.
- Bowl games are postseason college football games in the United States.

sql:
SELECT team_name
FROM teams
ORDER BY team_name;

SELECT COUNT(prediction_id) AS total_predictions
FROM predictions
WHERE user_id = (SELECT user_id FROM users WHERE username = 'analyst_user');

SELECT COUNT(*) AS total_games
FROM matchups
WHERE team1_id = 1 OR team2_id = 1;

SELECT bowl_name
FROM bowls
ORDER BY date DESC, bowl_name ASC;

SELECT bowl_name, date
FROM bowls
ORDER BY date DESC;
